from fastapi import FastAPI
from pydantic import BaseModel

app = FastAPI()

class Producto(BaseModel):
    nombre: str
    precio: float

@app.post("/productos/")
async def crear_producto(producto: Producto):
    # Pydantic valida automáticamente que los tipos sean correctos
    return {"mensaje": f"Producto {producto.nombre} guardado", "total": producto.precio * 1.21}

@app.get("/")
async def inicio():
    return {"tech": "TechPulse ES"}

from flask import Flask, jsonify

app = Flask(__name__)

@app.route('/usuario/<nombre>')
def saludar(nombre):
    # Retorna un JSON con un saludo personalizado
    datos = {"usuario": nombre, "estado": "conectado", "portal": "TechPulse ES"}
    return jsonify(datos)

if __name__ == '__main__':
    # Inicia el servidor en modo depuración
    app.run(debug=True)

import scrapy

class BlogSpider(scrapy.Spider):
    name = 'blog_spider'
    start_urls = ['https://techpulse.es/blog']

    def parse(self, response):
        # Extraemos todos los títulos de artículos usando selectores CSS
        for articulo in response.css('article.post'):
            yield {
                'titulo': articulo.css('h2::text').get(),
                'link': articulo.css('a::attr(href)').get(),
            }
